<?php
namespace App\Services\WarqnaPro;

use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Schema;

class StoreCatalogService
{
    public function sync(): void
    {
        if(!Schema::hasTable('store_items')) return;
        foreach(array_merge($this->pashaItems(), $this->tableSkins(), $this->cardBacks(), $this->nameFrames()) as $item) $this->upsert($item);
        // v131: remove duplicates and keep one clean Pasha plan per duration.
        $keep=array_column($this->pashaItems(),'key');
        DB::table('store_items')->where('category','pasha')->whereNotIn('key',$keep)->update(['active'=>false,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->whereIn('duration_days',[1,3,7,30,90,365])->whereNotIn('key',$keep)->update(['active'=>false,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->where('duration_days',7)->where('key','!=','pasha_7_days_v128')->update(['active'=>false,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->where('duration_days',30)->where('key','!=','pasha_30_days_v128')->update(['active'=>false,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->where('duration_days',365)->where('key','!=','pasha_365_days_v128')->update(['active'=>false,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->where('key','pasha_7_days_v128')->update(['price'=>10000,'duration_days'=>7,'active'=>true,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->where('key','pasha_30_days_v128')->update(['price'=>38000,'duration_days'=>30,'active'=>true,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->where('key','pasha_365_days_v128')->update(['price'=>300000,'duration_days'=>365,'active'=>true,'updated_at'=>now()]);
        // v134: keep only curated 50 tables; hide old repeated/WZ table rows from previous versions.
        $tableKeep=array_column($this->tableSkins(),'key');
        DB::table('store_items')->where('category','table')->whereNotIn('key',$tableKeep)->update(['active'=>false,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->where('key','pasha_1_day_v132')->update(['price'=>1700,'duration_days'=>1,'active'=>true,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->where('key','pasha_3_days_v132')->update(['price'=>5000,'duration_days'=>3,'active'=>true,'updated_at'=>now()]);
        DB::table('store_items')->where('category','pasha')->where('key','pasha_90_days_v132')->update(['price'=>105000,'duration_days'=>90,'active'=>true,'updated_at'=>now()]);

    }

    private function upsert(array $item): void
    {
        DB::table('store_items')->updateOrInsert(['key'=>$item['key']],[
            'name'=>json_encode(['ar'=>$item['ar'],'en'=>$item['en'] ?? $item['key']],JSON_UNESCAPED_UNICODE),
            'category'=>$item['category'],
            'price'=>$item['price'],
            'duration_days'=>$item['duration_days'] ?? null,
            'payload'=>json_encode($item['payload'] ?? [],JSON_UNESCAPED_UNICODE),
            'active'=>true,
            'created_at'=>now(),
            'updated_at'=>now(),
        ]);
    }

